module ip_checksum(  
    input [79:0] data, // 5 x 16-bit data  
    output reg [15:0] checksum  
);  
    integer i;  
    reg [31:0] checksum_sum;  

    always @(*) begin  
        checksum_sum = 0;  
        for (i = 0; i < 5; i = i + 1) begin  
            checksum_sum = checksum_sum + data[16*i +: 16];  
        end  
        // Add carry  
        checksum_sum = (checksum_sum >> 16) + (checksum_sum & 16'hFFFF);  
        // One's complement  
        checksum = ~checksum_sum[15:0];  
    end  
endmodule
